powershell -Command "
Add-Type -AssemblyName System.Drawing
Add-Type -AssemblyName System.Windows.Forms

# PDF 텍스트 추출을 위해 이미지로 변환 후 OCR은 무겁고
# pdftotext 설치 확인
try {
  $result = & pdftotext.exe 'XGI_XGR_XEC_XMC_Instruction_Manual_V4.0_210721_KR.pdf' - 2>&1 | Select-Object -First 100
  Write-Output \$result
} catch {
  Write-Output 'pdftotext not found'
}
"
